// API ?箇?頝臬?
const API_BASE = process.env.NEXT_PUBLIC_API_URL || "http://localhost:8000"

// ??蝯?憿?
interface SearchResult {
    lat: number
    lng: number
    name: string
    address?: string
    type?: string
}

// ??甇瑕 Hook
const HISTORY_KEY = "map_search_history"
function useSearchHistory() {
    const [history, setHistory] = useState<SearchResult[]>(() => {
        if (typeof window === 'undefined') return []
        try {
            const stored = localStorage.getItem(HISTORY_KEY)
            return stored ? JSON.parse(stored) : []
        } catch { return [] }
    })

    const addToHistory = useCallback((item: SearchResult) => {
        setHistory(prev => {
            const updated = [item, ...prev.filter(h => h.name !== item.name)].slice(0, 5)
            localStorage.setItem(HISTORY_KEY, JSON.stringify(updated))
            return updated
        })
    }, [])

    // ?? 皜甇瑕閮?
    const clearHistory = useCallback(() => {
        setHistory([])
        localStorage.removeItem(HISTORY_KEY)
    }, [])

    return { history, addToHistory, clearHistory }
}

// 頝舐?閬? Hook (雿輻敺垢 /api/route 隞??)
function useRoute(markersKey: string, markers: MarkerData[], mode: string, optimize: boolean = false) {
    const [route, setRoute] = useState<GeoJSON.Feature | null>(null)
    const [routeInfo, setRouteInfo] = useState<{ distance: string; duration: string; source?: string } | null>(null)
    const [loading, setLoading] = useState(false)

    useEffect(() => {
        if (markers.length < 2) {
            setRoute(null)
            setRouteInfo(null)
            return
        }

        const fetchRoute = async () => {
            setLoading(true)

            // ???? markers
            const stopsPayload = markers.map(m => ({ lat: m.lat, lng: m.lng, name: m.place }))

            // 撽?摨扳????吭r
            const validStops = stopsPayload.filter(s =>
                s.lat && s.lng &&
                typeof s.lat === 'number' && typeof s.lng === 'number' &&
                s.lat !== 0 && s.lng !== 0
            )

            if (validStops.length < 2) {
                console.warn("?? [Route Debug] 撠 2 ???漣璅?頝喲?頝舐?閮?")
                setRoute(null)
                setRouteInfo(null)
                setLoading(false)
                return
            }

            // ?? 瑼Ｘ葫頝典??楝蝺?(頝典?/頝冽絲) - 蝺臬漲撌株???5 摨西??箄楊??r
            const lats = validStops.map(s => s.lat)
            const latSpan = Math.max(...lats) - Math.min(...lats)

            if (latSpan > 5) {
                console.warn("?? [Route Debug] 頝典??楝蝺?(蝺臬漲撌?", latSpan.toFixed(2), "摨?嚗蝙?函蝺?")
                // ?? 蝜芾ˊ?渡?????? (??銵函內?郊銵楝蝺?
                const straightLineRoute: GeoJSON.Feature = {
                    type: "Feature",
                    properties: {},
                    geometry: {
                        type: "LineString",
                        coordinates: validStops.map(s => [s.lng, s.lat])
                    }
                }
                setRoute(straightLineRoute)
                setRouteInfo({
                    distance: "頝典??

straight-line"
                })
                setLoading(false)
                return
            }

            try {
                const res = await fetch(`${API_BASE}/api/route`, {
                    method: "POST",
                    headers: { "Content-Type": "application/json" },
                    body: JSON.stringify({
                        stops: validStops,  // ?芸???漣璅r
                        mode,
                        optimize
                    })
                })

                if (!res.ok) {
                    const errorText = await res.text()
                    console.error("??[Route Debug] API Error:", res.status, errorText)
                    throw new Error(`Route API failed: ${res.status}`)
                }

                const data = await res.json()

                if (data.route) {
                    setRoute(data.route)
                    setRouteInfo({
                        distance: data.distance,
                        duration: data.duration,
                        source: data.source
                    })
                }
            } catch (e) {
                console.error("??[Route Debug] Fetch error:", e)
                // ??摰嚗??方楝蝺?銝援瞏豹r
                setRoute(null)
                setRouteInfo(null)
            } finally {
                setLoading(false)
            }
        }

        fetchRoute()
    }, [markersKey, mode, optimize])

    return { route, routeInfo, loading }
}

interface DayMapProps {
    activities: Activity[]
    onAddPOI?: (poi: POIBasicData, time: string, notes?: string) => void
    dailyLoc?: { lat: number; lng: number; name?: string }  // ?? ?嗆?身銝剖?暺r
    tripTitle?: string  // ?? 銵?璅?嚗?潭?賣?撠?
}

export default function DayMap({ activities, onAddPOI, dailyLoc, tripTitle }: DayMapProps) {
    const mapRef = useRef<MapRef>(null)
    const [mode, setMode] = useState<'walk' | 'drive' | 'transit'>('walk')
    const [popupInfo, setPopupInfo] = useState<MarkerData | null>(null)
    const [mapLoaded, setMapLoaded] = useState(false)

    // ?? Terra-Cognita: 摨?璅∪? (璅?/銵?)
    const [mapMode, setMapMode] = useState<'standard' | 'satellite'>('standard')

    // ?? POI Detail Drawer ??r
    // ?? POI Detail Drawer ??r
    const [poiDrawerOpen, setPoiDrawerOpen] = useState(false)
    const [selectedPOI, setSelectedPOI] = useState<POIBasicData | null>(null)

    // ?? ????r
    const [isSearchOpen, setIsSearchOpen] = useState(false)
    const [isSearchMinimized, setIsSearchMinimized] = useState(false)  // ?? ?撠???r
    const [query, setQuery] = useState("")
    const [results, setResults] = useState<SearchResult[]>([])
    const [isTyping, setIsTyping] = useState(false)     // ?? 頛詨銝哨?debounce ??嚗r
    const [isSearching, setIsSearching] = useState(false)
    const [aiSearching, setAiSearching] = useState(false)
    const { history, addToHistory, clearHistory } = useSearchHistory()
    const inputRef = useRef<HTMLInputElement>(null)

    // ?? 頛詨霈??嚗??喳?擖?
    const handleQueryChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const value = e.target.value
        setQuery(value)
        if (value.length >= 2) {
            setIsTyping(true)
        } else {
            setIsTyping(false)
            setResults([])
        }
    }

    // ?? ?芸?蝢拙?雿???(?誨??bug ??GeolocateControl)
    const [userLocation, setUserLocation] = useState<{ lat: number; lng: number } | null>(null)
    const [isLocating, setIsLocating] = useState(false)

    // ?? ??蝯?璅?嚗??脣之?剝?嚗r
    const [searchResultMarker, setSearchResultMarker] = useState<{ lat: number; lng: number; name: string } | null>(null)


    const handleLocateMe = () => {
        if (!("geolocation" in navigator)) {
            alert("?函??汗?其??舀摰??")
            return
        }
        setIsLocating(true)
        navigator.geolocation.getCurrentPosition(
            (position) => {
                const { latitude, longitude } = position.coords
                setUserLocation({ lat: latitude, lng: longitude })
                setIsLocating(false)
                // 憌?冽雿蔭
                if (mapRef.current) {
                    mapRef.current.flyTo({
                        center: [longitude, latitude],
                        zoom: 15,
                        duration: 2000
                    })
                }
            },
            (error) => {
                setIsLocating(false)
                console.error("Geolocation error:", error)
                if (error.code === error.PERMISSION_DENIED) {
                    alert("摰?甈?鋡急?蝯?隢?閮梁汗?函???蝵娉

?⊥??脣?雿蔭: " + error.message)
                }
            },
            { enableHighAccuracy: true, timeout: 30000, maximumAge: 0 }
        )
    }


    // Debounced ??
    useEffect(() => {
        if (!isSearchOpen || query.length < 2) {
            setResults([])
            setIsTyping(false)
            return
        }

        const currentQuery = query  // ?? 敹怎?脫迫蝡嗆?

        const timer = setTimeout(async () => {
            setIsTyping(false)    // debounce 蝯?
            setIsSearching(true)
            setResults([])  // Anti-flicker: clear old results before new search
            try {
                const center = mapRef.current?.getCenter()
                const data = await geocodeApi.search({
                    query: currentQuery,
                    limit: 5,
                    tripTitle,
                    lat: center?.lat,
                    lng: center?.lng
                })
                // ?? ?芸 query 隞?寥???豹r
                if (currentQuery === query) {
                    setResults(data.results || [])
                }
            } catch {
                if (currentQuery === query) {
                    setResults([])
                }
            } finally {
                setIsSearching(false)
            }
        }, 300)

        return () => clearTimeout(timer)
    }, [query, isSearchOpen, tripTitle])

    // ?芸? focus
    useEffect(() => {
        if (isSearchOpen && inputRef.current) {
            setTimeout(() => inputRef.current?.focus(), 100)
        }
    }, [isSearchOpen])

    // 憌??雿蔭
    const flyTo = useCallback((result: SearchResult) => {
        console.log("?? FlyTo triggered:", result)
        addToHistory(result)
        setQuery(result.name)
        setIsSearchOpen(false)

        if (!mapRef.current) {
            console.error("??Map ref is null")
            return
        }

        const lng = Number(result.lng)
        const lat = Number(result.lat)

        if (isNaN(lng) || isNaN(lat)) {
            console.error("??Invalid coordinates:", result)
            return
        }

        mapRef.current.flyTo({
            center: [lng, lat],
            zoom: 16,
            duration: 1500
        })

        // ?? 閮剔蔭??蝯?璅?嚗??脣之?剝?嚗r
        setSearchResultMarker({ lat, lng, name: result.name })

        // 撱箇? POI 銝阡???Drawer
