    }, [addToHistory])

    // AI 隤??? - ?脰雓?嚗?函?撖?POI 鞈?
    const handleAISearch = useCallback(async () => {
        if (!query) return

        const center = mapRef.current?.getCenter()
        const lat = center?.lat || 35.6895
        const lng = center?.lng || 139.6917

        setAiSearching(true)
        try {
            const response = await fetch(
                `${API_BASE}/api/ai/smart-search`,
                {
                    method: "POST",
                    headers: { "Content-Type": "application/json" },
                    body: JSON.stringify({
                        query,
                        lat,
                        lng,
                        region: tripTitle,
                        trip_title: tripTitle,
                        api_key: localStorage.getItem("user_gemini_key"),
                        max_results: 5
                    })
                }
            )

            if (!response.ok) throw new Error("Smart search failed")
            const data = await response.json()

            console.log("?? Smart Search Result:", data)

            // ???唳撘?r
            if (data.status === "success" && data.results && data.results.length > 0) {
                // 憌蝚砌????r
                const first = data.results[0]
                if (first.lat && first.lng) {
                    flyTo({
                        lat: first.lat,
                        lng: first.lng,
                        name: first.name,
                        address: first.address || ""
                    })
                }

                // 閮剔蔭蝯??”嚗?函?撖?POI 鞈?嚗 AI ???膩嚗r
                setResults(data.results.map((r: { name: string; address?: string; lat?: number; lng?: number; distance?: number }) => ({
                    name: r.name,
                    address: r.address || (r.distance ? `頝 ${r.distance}m` : ""),
                    lat: r.lat,
                    lng: r.lng
                })))
            } else if (data.status === "not_found") {
                // ?Ⅱ?銝??銝雓r
                console.log("?? Not found:", data.message)
                setResults([])  // 皜征蝯?
            }
        } catch (error) {
            console.error("AI Search Error:", error)
        } finally {
            setAiSearching(false)
        }
    }, [query, tripTitle, flyTo])

    // ?蕪?箸?摨扳??暺r
    const markers = activities
        .filter((a): a is Activity & { lat: number; lng: number } =>
            typeof a.lat === 'number' && typeof a.lng === 'number'
        )
        .map((a, index) => ({
            ...a,
            number: index + 1
        })) as MarkerData[]

    const markersKey = markers.map(m => `${m.lat},${m.lng}`).join('|')
    const { route, routeInfo, loading } = useRoute(markersKey, markers, mode)

    // ?? Terra-Cognita: ???惜?航??吭r
    const updateLayerVisibility = useCallback((isSatellite: boolean) => {
        const map = mapRef.current?.getMap()
        if (!map || !map.isStyleLoaded()) return

        const layers = map.getStyle()?.layers || []

        layers.forEach(layer => {
            const layerId = layer.id.toLowerCase()

            // 銵?璅∪?嚗???舫??惜
            if (MAP_STYLES.LAYERS_HIDE_ON_SATELLITE.some(hide => layerId.includes(hide))) {
                map.setLayoutProperty(layer.id, 'visibility', isSatellite ? 'none' : 'visible')
            }

            // 銵?璅∪?嚗矽?湧?頝舫?摨吒r
            if (MAP_STYLES.LAYERS_TRANSPARENT_ON_SATELLITE.some(road => layerId.includes(road))) {
                if (layer.type === 'line') {
                    try {
                        map.setPaintProperty(
                            layer.id,
                            'line-opacity',
                            isSatellite ? MAP_STYLES.ROAD_OPACITY_ON_SATELLITE : 1
                        )
                    } catch (_e) {
                        // ???惜?航銝?湔迨撅祆吭r
                    }
                }
            }
        })

        // ??銵??惜?航??吭r
        if (map.getLayer('satellite-layer')) {
            map.setLayoutProperty('satellite-layer', 'visibility', isSatellite ? 'visible' : 'none')
        }
    }, [])

    // 璅∪?????啣?撅么r
    useEffect(() => {
        if (mapLoaded) {
            updateLayerVisibility(mapMode === 'satellite')
        }
    }, [mapMode, mapLoaded, updateLayerVisibility])

    // ?芸?蝮格?唳??? (?芸?活頛?銵?
    const hasInitialized = useRef(false)

    const fitBounds = useCallback(() => {
        if (markers.length === 0 || !mapRef.current || !mapLoaded) return
        if (hasInitialized.current) return  // ?? ?芸銵?甈﹏r

        hasInitialized.current = true

        if (markers.length === 1) {
            mapRef.current.flyTo({
                center: [markers[0].lng, markers[0].lat],
                zoom: 15
            })
            return
        }

        const lngs = markers.map(m => m.lng)
        const lats = markers.map(m => m.lat)
        const bounds: LngLatBoundsLike = [
            [Math.min(...lngs), Math.min(...lats)],
            [Math.max(...lngs), Math.max(...lats)]
        ]

        mapRef.current.fitBounds(bounds, { padding: 60, duration: 500 })
    }, [markers, mapLoaded])

    useEffect(() => {
        const timer = setTimeout(fitBounds, 100)
        return () => clearTimeout(timer)
    }, [fitBounds])

    // ?? ?啣?頛敺溶????撅么r
    const handleMapLoad = useCallback(() => {
        setMapLoaded(true)

        const map = mapRef.current?.getMap()
        if (!map) return

        // ?? ??蝻箏仃??璅????踵??箇征??嚗??console ?航炊嚗r
        map.on('styleimagemissing', (e) => {
            const id = e.id
            // 撱箇? 1x1 ????雿 fallback
            if (!map.hasImage(id)) {
                map.addImage(id, { width: 1, height: 1, data: new Uint8Array([0, 0, 0, 0]) })
            }
        })

        // 瘛餃? Esri 銵? Source
        if (!map.getSource('satellite')) {
            map.addSource('satellite', {
                type: 'raster',
                tiles: [MAP_STYLES.SATELLITE],
                tileSize: 256,
                attribution: '穢 Esri'
            })
        }

        // 瘛餃?銵??惜 (?摨惜嚗?閮剝??
        if (!map.getLayer('satellite-layer')) {
            const firstLayerId = map.getStyle()?.layers?.[0]?.id
            map.addLayer({
                id: 'satellite-layer',
                type: 'raster',
                source: 'satellite',
                layout: { visibility: 'none' },
                paint: { 'raster-opacity': 1 }
            }, firstLayerId)
        }

        // ?? 3D 撱箇?撅?(OpenMapTiles Schema)
        if (!map.getLayer('3d-buildings')) {
            // ?曉??璅惜撅斤? ID (蝣箔? 3D 撱箇????銝)
            const layers = map.getStyle()?.layers || []
            const labelLayerId = layers.find(
                (layer) => layer.type === 'symbol' && 'layout' in layer && layer.layout?.['text-field']
            )?.id

            map.addLayer({
                id: '3d-buildings',
                source: 'openmaptiles',
                'source-layer': 'building',
                filter: ['==', 'extrude', 'true'],
                type: 'fill-extrusion',
                minzoom: MAP_STYLES.BUILDING_3D.MIN_ZOOM,
                paint: {
                    'fill-extrusion-color': MAP_STYLES.BUILDING_3D.COLOR,
                    'fill-extrusion-height': [
                        'interpolate',
                        ['linear'],
                        ['zoom'],
                        15, 0,
                        15.05, ['get', 'render_height']
                    ],
                    'fill-extrusion-base': [
                        'interpolate',
                        ['linear'],
                        ['zoom'],
                        15, 0,
                        15.05, ['get', 'render_min_height']
                    ],
                    'fill-extrusion-opacity': MAP_STYLES.BUILDING_3D.OPACITY
                }
            }, labelLayerId)
        }

        // ?? POI 暺?鈭辣 (Progressive Intelligence Layer 1)
        map.on('click', (e) => {
            // ?亥岷暺?雿蔭??POI ?惜
            const features = map.queryRenderedFeatures(e.point, {
                layers: map.getStyle()?.layers
                    ?.filter(l => l.id.includes('poi') || l.id.includes('label'))
                    .map(l => l.id) || []
            })

            if (features.length > 0) {
                const feature = features[0]
                const props = feature.properties || {}
                const coords = feature.geometry.type === 'Point'
                    ? (feature.geometry as GeoJSON.Point).coordinates
                    : [e.lngLat.lng, e.lngLat.lat]

                // 瑽遣 POI ?箇?鞈?
                const poiData: POIBasicData = {
                    name: props.name || props.name_en || '?芰?圈?',
                    type: props.class || props.subclass || props.type || 'place',
                    lat: coords[1] as number,
                    lng: coords[0] as number,
                    address: props.address || props.addr_street,
                    phone: props.phone,
                    website: props.website,
                    opening_hours: props.opening_hours
