"use client"

import { useState, useEffect } from "react"
import { motion, AnimatePresence } from "framer-motion"
import Image from "next/image"

export function SplashScreen() {
    const [show, setShow] = useState(true)
    const [isStandalone, setIsStandalone] = useState(false)

    // eslint-disable-next-line react-hooks/exhaustive-deps -- ?敹???憪??摩嚗?冽?頛??瑁?銝甈﹏r
    useEffect(() => {
        // 瑼Ｘ?臬??PWA 璅∪?
        const standalone = window.matchMedia('(display-mode: standalone)').matches ||
            (window.navigator as unknown as { standalone?: boolean }).standalone === true
        setIsStandalone(standalone)

        // 瑼Ｘ?臬撌脩?憿舐內???? session嚗r
        const hasShown = sessionStorage.getItem('splash_shown')
        if (hasShown || !standalone) {
            setShow(false)
            return
        }

        // ?蝯?敺?r
        const timer = setTimeout(() => {
            setShow(false)
            sessionStorage.setItem('splash_shown', 'true')
        }, 2000)

        return () => clearTimeout(timer)
    }, [])

    // ??PWA 璅∪?銝＊蝷暝r
    if (!isStandalone) return null

    return (
        <AnimatePresence>
            {show && (
                <motion.div
                    className="fixed inset-0 z-[9999] flex flex-col items-center justify-center bg-gradient-to-b from-stone-50 via-white to-stone-100"
                    initial={{ opacity: 1 }}
                    exit={{ opacity: 0 }}
                    transition={{ duration: 0.5 }}
                >
                    {/* ?鋆ˇ - ?湔楚??敶?*/}
                    <div className="absolute inset-0 overflow-hidden">
                        <motion.div
                            className="absolute -top-32 -right-32 w-80 h-80 bg-stone-200/20 rounded-full blur-3xl"
                            initial={{ scale: 0.8, opacity: 0 }}
                            animate={{ scale: 1, opacity: 1 }}
                            transition={{ duration: 1, ease: "easeOut" }}
                        />
                        <motion.div
                            className="absolute -bottom-32 -left-32 w-80 h-80 bg-stone-200/20 rounded-full blur-3xl"
                            initial={{ scale: 0.8, opacity: 0 }}
                            animate={{ scale: 1, opacity: 1 }}
                            transition={{ duration: 1, delay: 0.2, ease: "easeOut" }}
                        />
                    </div>

                    {/* Icon ? */}
                    <motion.div
                        initial={{ scale: 0, rotate: -180 }}
                        animate={{ scale: 1, rotate: 0 }}
                        transition={{
                            type: "spring",
                            stiffness: 200,
                            damping: 15,
                            duration: 0.8
                        }}
                        className="relative"
                    >
                        <motion.div
                            animate={{
                                scale: [1, 1.08, 1],
                            }}
                            transition={{
                                duration: 2,
                                repeat: Infinity,
                                ease: "easeInOut"
                            }}
                            className="w-32 h-32"
                        >
                            <Image
                                src="/icon.png"
                                alt="Tabidachi"
                                width={128}
                                height={128}
                                className="w-full h-full object-contain drop-shadow-lg"
                                priority
                            />
                        </motion.div>

                        {/* ???? */}
                        <motion.div
                            className="absolute inset-0 rounded-3xl"
                            initial={{ boxShadow: "0 0 0 0 rgba(251, 191, 36, 0)" }}
                            animate={{
                                boxShadow: [
                                    "0 0 0 0 rgba(251, 191, 36, 0.4)",
                                    "0 0 0 20px rgba(251, 191, 36, 0)",
                                ]
                            }}
                            transition={{
                                duration: 1.5,
                                repeat: Infinity,
                                ease: "easeOut"
                            }}
                        />
                    </motion.div>

                    {/* ?? */}
                    <motion.div
                        initial={{ opacity: 0, y: 20 }}
                        animate={{ opacity: 1, y: 0 }}
                        transition={{ delay: 0.5, duration: 0.5 }}
                        className="mt-8 text-center"
                    >
                        <h1 className="text-3xl font-bold bg-gradient-to-r from-amber-600 to-orange-500 bg-clip-text text-transparent">
                            Tabidachi
                        </h1>
                        <p className="text-sm text-slate-500 mt-1">AI Travel Planner</p>
                    </motion.div>

                    {/* Loading ?內??*/}
                    <motion.div
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        transition={{ delay: 0.8 }}
                        className="mt-8"
                    >
                        <div className="flex gap-1">
                            {[0, 1, 2].map((i) => (
                                <motion.div
                                    key={i}
                                    className="w-2 h-2 rounded-full bg-amber-400"
                                    animate={{
                                        scale: [1, 1.5, 1],
                                        opacity: [0.5, 1, 0.5]
